import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Menu, X, Instagram, Youtube, Facebook, ChevronRight, ChevronLeft, MapPin, Clock, Phone, AlertCircle, CheckCircle2 } from 'lucide-react';
import { THEMES, STORE_INFO, INTRO_POINTS } from './constants';
import Home from './components/Home';
import ThemeReservation from './components/ThemeReservation';
import ThemeDetail from './components/ThemeDetail';
import BookingForm from './components/BookingForm';
import BookingSuccess from './components/BookingSuccess';

const Header = () => {
  const location = useLocation();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isHome = location.pathname === '/';
  const headerBg = isHome 
    ? (isScrolled ? 'bg-[#121212]/95 border-b border-white/10' : 'bg-transparent')
    : 'bg-[#121212] border-b border-white/10';

  const navItems = [
    { name: '홈', path: '/' },
    { name: '이용안내', path: '/info' },
    { name: '테마예약', path: '/reservation' },
    { name: '공지사항', path: '/notice' },
    { name: '문의하기', path: '/contact' }
  ];

  return (
    <header className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${headerBg}`}>
      <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
        <Link to="/" className="text-2xl font-bold tracking-tighter text-white">
          CRIME <span className="text-red-600">SCENERS</span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex space-x-10">
          {navItems.map((item) => (
            <Link 
              key={item.name} 
              to={item.path} 
              className="text-sm font-medium hover:text-red-500 transition-colors"
            >
              {item.name}
            </Link>
          ))}
        </nav>

        {/* Mobile Toggle */}
        <button 
          className="md:hidden text-white"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
        >
          {isMenuOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {isMenuOpen && (
        <div className="md:hidden fixed inset-0 top-20 bg-[#121212] z-40 p-6 flex flex-col space-y-6">
          {navItems.map((item) => (
            <Link 
              key={item.name} 
              to={item.path} 
              className="text-xl font-bold border-b border-white/5 pb-4"
              onClick={() => setIsMenuOpen(false)}
            >
              {item.name}
            </Link>
          ))}
        </div>
      )}
    </header>
  );
};

const Footer = () => (
  <footer className="bg-black border-t border-white/5 py-12 px-6">
    <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-center space-y-8 md:space-y-0">
      <div>
        <h2 className="text-xl font-bold mb-4">CRIME SCENERS</h2>
        <div className="text-sm text-[#b3b3b3] space-y-1">
          <p>{STORE_INFO.businessInfo}</p>
          <p>주소: {STORE_INFO.address}</p>
          <p>연락처: {STORE_INFO.phone}</p>
          <p>© 2024 CRIME SCENERS. All rights reserved.</p>
        </div>
      </div>
      <div className="flex space-x-6">
        <a href="#" className="hover:text-red-500 transition-colors"><Instagram size={24} /></a>
        <a href="#" className="hover:text-red-500 transition-colors"><Youtube size={24} /></a>
        <a href="#" className="hover:text-red-500 transition-colors"><Facebook size={24} /></a>
      </div>
    </div>
  </footer>
);

const App = () => {
  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col">
        <Header />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/reservation" element={<ThemeReservation />} />
            <Route path="/theme/:id" element={<ThemeDetail />} />
            <Route path="/booking/:themeId/:date/:time" element={<BookingForm />} />
            <Route path="/success" element={<BookingSuccess />} />
            {/* Placeholder routes */}
            <Route path="/info" element={<Placeholder title="이용안내" />} />
            <Route path="/notice" element={<Placeholder title="공지사항" />} />
            <Route path="/contact" element={<Placeholder title="문의하기" />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </HashRouter>
  );
};

const Placeholder = ({ title }: { title: string }) => (
  <div className="pt-32 pb-20 px-6 text-center max-w-2xl mx-auto min-h-[60vh]">
    <h1 className="text-4xl font-bold mb-6">{title}</h1>
    <p className="text-[#b3b3b3]">준비 중인 페이지입니다. 조속히 업데이트 하겠습니다.</p>
    <div className="mt-10 flex justify-center">
        <Link to="/" className="px-6 py-3 bg-red-600 rounded text-white font-bold hover:bg-red-700 transition-colors">홈으로 돌아가기</Link>
    </div>
  </div>
);

export default App;

import React from 'react';
import { Link } from 'react-router-dom';
import { THEMES } from '../constants';
import { ChevronRight } from 'lucide-react';

