import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { THEMES } from '../constants';
import { Clock, Users, ArrowLeft, Calendar as CalendarIcon, AlertTriangle } from 'lucide-react';

const ThemeDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const theme = THEMES.find(t => t.id === id);
  const [selectedDate, setSelectedDate] = useState<string | null>(null);

  if (!theme) return <div className="pt-32 px-6 text-center">테마를 찾을 수 없습니다.</div>;

  // Mocked time slots for the example
  const timeSlots = [
    { time: '11:00', current: 0, max: theme.maxPlayers, isClosed: false },
    { time: '13:00', current: theme.maxPlayers, max: theme.maxPlayers, isClosed: true },
    { time: '15:30', current: 2, max: theme.maxPlayers, isClosed: false },
    { time: '18:00', current: 0, max: theme.maxPlayers, isClosed: false },
    { time: '20:30', current: theme.minPlayers, max: theme.maxPlayers, isClosed: false },
  ];

  const handleTimeSelect = (time: string, isClosed: boolean) => {
    if (isClosed) return;
    if (!selectedDate) {
      alert('날짜를 먼저 선택해주세요.');
      return;
    }
    navigate(`/booking/${theme.id}/${selectedDate}/${time}`);
  };

  const dates = Array.from({ length: 7 }, (_, i) => {
    const d = new Date();
    d.setDate(d.getDate() + i);
    return d.toISOString().split('T')[0];
  });

  return (
    <div className="pt-32 pb-24 px-6 max-w-7xl mx-auto">
      <Link to="/reservation" className="inline-flex items-center text-[#b3b3b3] hover:text-white mb-8 gap-2 group transition-colors">
        <ArrowLeft size={20} className="group-hover:-translate-x-1 transition-transform" /> 리스트로 돌아가기
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
        {/* Left: Info */}
        <div>
          <div className="aspect-[3/4] w-full max-w-[500px] rounded-2xl overflow-hidden mb-10 shadow-2xl">
            <img src={theme.posterUrl} alt={theme.title} className="w-full h-full object-cover" />
          </div>

          <h1 className="text-4xl font-bold mb-4">{theme.title}</h1>
          <div className="flex flex-wrap gap-6 mb-8">
            <div className="flex items-center gap-2 text-[#b3b3b3]">
              <Clock size={20} className="text-red-500" /> <span>{theme.duration}분</span>
            </div>
            <div className="flex items-center gap-2 text-[#b3b3b3]">
              <Users size={20} className="text-red-500" /> <span>{theme.minPlayers}~{theme.maxPlayers}인</span>
            </div>
            <div className="flex items-center gap-2 text-[#b3b3b3]">
              <span className="text-red-500 font-bold">난이도</span> <span>{'★'.repeat(theme.difficulty)}</span>
            </div>
          </div>

          <div className="space-y-6">
            <h3 className="text-xl font-bold border-l-4 border-red-600 pl-4">SYNOPSIS</h3>
            <p className="text-[#b3b3b3] leading-relaxed text-lg whitespace-pre-wrap">
              {theme.synopsis}
            </p>
            <div className="p-6 bg-[#1a1a1a] rounded-xl border border-white/5">
                <p className="text-sm font-medium text-red-400 flex items-center gap-2 mb-2">
                    <AlertTriangle size={16} /> 예약 안내사항
                </p>
                <ul className="text-xs text-[#b3b3b3] space-y-2 list-disc pl-4">
                    <li>예약 10분 전까지 도착하여 역할을 배정받으셔야 합니다.</li>
                    <li>크라임씬 특성상 지각 시 게임 참여에 큰 지장이 생길 수 있습니다.</li>
                    <li>스포일러 방지를 위해 기밀 유지 서약서를 작성하게 됩니다.</li>
                </ul>
            </div>
          </div>
        </div>

        {/* Right: Booking */}
        <div className="bg-[#1a1a1a] p-8 md:p-12 rounded-3xl border border-white/5 self-start sticky top-32">
          <h2 className="text-2xl font-bold mb-8 flex items-center gap-3">
            <CalendarIcon className="text-red-600" /> 예약하기
          </h2>

          <div className="mb-8">
            <p className="text-sm font-medium mb-4">날짜 선택</p>
            <div className="grid grid-cols-4 md:grid-cols-7 gap-2">
              {dates.map((date) => {
                const day = new Date(date).getDate();
                const isSelected = selectedDate === date;
                return (
                  <button
                    key={date}
                    onClick={() => setSelectedDate(date)}
                    className={`flex flex-col items-center py-3 rounded-lg border transition-all ${
                      isSelected ? 'bg-red-600 border-red-600 text-white' : 'bg-transparent border-white/10 text-[#b3b3b3] hover:border-white/30'
                    }`}
                  >
                    <span className="text-xs">{new Date(date).toLocaleDateString('ko-KR', { weekday: 'short' })}</span>
                    <span className="text-lg font-bold">{day}</span>
                  </button>
                );
              })}
            </div>
          </div>

          <div>
            <p className="text-sm font-medium mb-4">시간 선택</p>
            <div className="space-y-3">
              {timeSlots.map((slot) => (
                <button
                  key={slot.time}
                  disabled={slot.isClosed}
                  onClick={() => handleTimeSelect(slot.time, slot.isClosed)}
                  className={`w-full flex items-center justify-between p-5 rounded-xl border transition-all ${
                    slot.isClosed 
                      ? 'bg-black/20 border-white/5 text-white/20 cursor-not-allowed opacity-50' 
                      : 'bg-white/5 border-white/10 text-white hover:border-red-600/50 hover:bg-white/10'
                  }`}
                >
                  <div className="flex items-center gap-4">
                    <span className="text-xl font-mono font-bold">{slot.time}</span>
                    <span className={`text-xs px-2 py-0.5 rounded border ${slot.isClosed ? 'border-white/20' : 'border-red-600/40 text-red-500'}`}>
                      {slot.isClosed ? '예약마감' : '예약가능'}
                    </span>
                  </div>
                  <div className="text-sm">
                    {slot.isClosed ? 'FULL' : `${slot.current}/${slot.max} 명`}
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ThemeDetail;

import React, { useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { THEMES } from '../constants';
import { ChevronLeft, Info, CheckCircle2 } from 'lucide-react';

const BookingForm = () => {
  const { themeId, date, time } = useParams();
  const navigate = useNavigate();
  const theme = THEMES.find(t => t.id === themeId);

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    participants: theme?.minPlayers || 4,
    isCloseRequested: false,
    notes: ''
  });

  if (!theme) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone) {
        alert('예약자 성함과 휴대폰 번호를 입력해 주세요.');
        return;
    }
    // Simulate API call
    console.log('Booking submitted:', { themeId, date, time, ...formData });
    navigate('/success', { state: { theme, date, time, ...formData } });
  };

  const showCloseOption = (theme.id === 'theme-2' && formData.participants >= 5) || 
                          (theme.id !== 'theme-2' && formData.participants >= 4);

  return (
    <div className="pt-32 pb-24 px-6 max-w-3xl mx-auto">
      <Link to={`/theme/${themeId}`} className="inline-flex items-center text-[#b3b3b3] hover:text-white mb-8 gap-1">
        <ChevronLeft size={20} /> 테마 상세로 돌아가기
      </Link>

      <div className="bg-[#1a1a1a] rounded-3xl border border-white/5 overflow-hidden">
        <div className="p-8 md:p-10 border-b border-white/5 bg-white/5">
            <h1 className="text-3xl font-bold mb-2">예약 정보 입력</h1>
            <p className="text-[#b3b3b3]">{theme.title} | {date} | {time}</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 md:p-10 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-[#b3b3b3]">예약자 성함</label>
              <input 
                type="text" 
                required
                className="w-full bg-black/40 border border-white/10 rounded-lg p-3 focus:outline-none focus:border-red-600 transition-colors"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-[#b3b3b3]">휴대폰 번호</label>
              <input 
                type="tel" 
                required
                placeholder="010-0000-0000"
                className="w-full bg-black/40 border border-white/10 rounded-lg p-3 focus:outline-none focus:border-red-600 transition-colors"
                value={formData.phone}
                onChange={(e) => setFormData({...formData, phone: e.target.value})}
              />
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-sm font-medium text-[#b3b3b3]">참여 인원 ({theme.minPlayers}~{theme.maxPlayers}인)</label>
            <div className="flex gap-4">
              {Array.from({ length: theme.maxPlayers - theme.minPlayers + 1 }, (_, i) => theme.minPlayers + i).map(num => (
                <button
                  key={num}
                  type="button"
                  onClick={() => setFormData({...formData, participants: num})}
                  className={`w-12 h-12 rounded-lg border font-bold transition-all ${
                    formData.participants === num 
                        ? 'bg-red-600 border-red-600 text-white' 
                        : 'bg-transparent border-white/10 text-[#b3b3b3] hover:border-white/30'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </div>

          {showCloseOption && (
            <div className="p-6 bg-red-950/20 border border-red-900/30 rounded-2xl flex items-start gap-4">
              <div className="pt-1">
                <input 
                  type="checkbox" 
                  id="closeBooking"
                  className="w-5 h-5 accent-red-600"
                  checked={formData.isCloseRequested}
                  onChange={(e) => setFormData({...formData, isCloseRequested: e.target.checked})}
                />
              </div>
              <label htmlFor="closeBooking" className="cursor-pointer">
                <p className="font-bold text-red-500 mb-1">예약 마감 요청</p>
                <p className="text-xs text-[#b3b3b3] leading-relaxed">
