                <textarea rows={3} className="w-full bg-black/40 border border-white/10 p-3 rounded-lg font-mono resize-none" 
                  value={settings.weekendSlots.join(', ')} 
                  onChange={e => setSettings({...settings, weekendSlots: e.target.value.split(',').map(s => s.trim())})} />
             </div>
