            <button onClick={addNotice} className="px-4 py-2 bg-white/10 rounded flex items-center gap-2 hover:bg-white/20 transition-all text-sm">
                <Plus size={16} /> 새 공지 추가
            </button>
        </div>
        <div className="space-y-4">
            {notices.map((n, idx) => (
                <div key={n.id} className="p-4 border border-white/5 bg-black/20 rounded-xl flex items-center gap-4">
                    <input className="bg-transparent border-b border-white/10 flex-grow py-1 font-bold" value={n.title} 
                        onChange={e => {
                            const updated = [...notices];
                            updated[idx].title = e.target.value;
                            setNotices(updated);
                            localStorage.setItem('cs_notices', JSON.stringify(updated));
                        }} />
                    <button onClick={() => {
                        const updated = notices.filter(item => item.id !== n.id);
                        setNotices(updated);
                        localStorage.setItem('cs_notices', JSON.stringify(updated));
                    }} className="text-white/20 hover:text-red-500"><Trash2 size={18} /></button>
                </div>
            ))}
        </div>
      </section>
    </div>
  );
};

