                <label className="text-sm text-white/60 mb-2 block">주말 타임 (쉼표로 구분)</label>
                <textarea rows={3} className="w-full bg-black/40 border border-white/10 p-3 rounded-lg font-mono resize-none focus:border-white outline-none" 
                  value={settings.weekendSlots.join(', ')} 
