import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { THEMES, DEFAULT_ADMIN_SETTINGS } from '../constants';
import { Calendar as CalendarIcon, Clock, Users, ArrowLeft, ChevronLeft, ChevronRight } from 'lucide-react';
import { AdminSettings, Theme } from '../types';

const ThemeDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [theme, setTheme] = useState<Theme | null>(null);

  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [settings, setSettings] = useState<AdminSettings>(DEFAULT_ADMIN_SETTINGS);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem('cs_admin_settings');
    if (savedSettings) setSettings(JSON.parse(savedSettings));

    // Load theme from dynamic list
    const savedThemes = localStorage.getItem('cs_themes');
    const themeList = savedThemes ? JSON.parse(savedThemes) : THEMES;
    const found = themeList.find((t: Theme) => t.id === id);
    if (found) setTheme(found);
  }, [id]);

  if (!theme) return <div className="pt-32 text-center">테마를 찾을 수 없습니다.</div>;

  const renderCalendar = () => {
    const year = currentMonth.getFullYear();
    const month = currentMonth.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const days = [];
    for (let i = 0; i < firstDay; i++) days.push(<div key={`empty-${i}`} className="p-4" />);
    for (let d = 1; d <= daysInMonth; d++) {
      const date = new Date(year, month, d);
      const isSelected = selectedDate?.toDateString() === date.toDateString();
      const isPast = date < new Date(new Date().setHours(0,0,0,0));

      days.push(
        <button
          key={d}
          disabled={isPast}
          onClick={() => setSelectedDate(date)}
          className={`p-4 rounded-lg border transition-all flex flex-col items-center ${
            isPast ? 'opacity-20 cursor-not-allowed' :
            isSelected ? 'bg-white border-white text-black font-bold' : 'hover:border-white border-white/10'
          }`}
        >
          <span className="text-lg">{d}</span>
        </button>
      );
    }
    return days;
  };

  const getSlots = () => {
    if (!selectedDate) return [];
    const day = selectedDate.getDay();
    const isWeekend = day === 0 || day === 6;
    return isWeekend ? settings.weekendSlots : settings.weekdaySlots;
  };

  return (
    <div className="pt-32 pb-24 px-6 max-w-7xl mx-auto">
      <Link to="/reservation" className="inline-flex items-center text-[#b3b3b3] hover:text-white mb-8 gap-2">
        <ArrowLeft size={20} /> 테마 리스트
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
        <div>
          <img src={theme.posterUrl} className="w-full max-w-[450px] aspect-[3/4] object-cover rounded-2xl shadow-2xl mb-8" />
          <h1 className="text-4xl font-bold mb-4">{theme.title}</h1>
          <p className="text-[#b3b3b3] text-lg leading-relaxed mb-8">{theme.synopsis}</p>
          <div className="flex gap-6 text-sm text-white/60">
            <span className="flex items-center gap-2"><Clock size={16} /> {theme.duration}분</span>
            <span className="flex items-center gap-2"><Users size={16} /> {theme.minPlayers}-{theme.maxPlayers}인</span>
          </div>
        </div>

        <div className="bg-[#1a1a1a] p-8 rounded-3xl border border-white/5">
          <div className="flex items-center justify-between mb-8">
            <h2 className="text-xl font-bold flex items-center gap-2"><CalendarIcon /> 날짜 선택</h2>
            <div className="flex items-center gap-4">
              <button onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() - 1)))}><ChevronLeft /></button>
              <span className="font-bold">{currentMonth.getFullYear()}년 {currentMonth.getMonth() + 1}월</span>
              <button onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() + 1)))}><ChevronRight /></button>
            </div>
          </div>

          <div className="grid grid-cols-7 gap-2 text-center text-xs text-white/40 mb-4 font-bold">
            {['일','월','화','수','목','금','토'].map(d => <div key={d}>{d}</div>)}
          </div>
          <div className="grid grid-cols-7 gap-2 mb-10">
            {renderCalendar()}
          </div>

          {selectedDate && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                <Clock size={18} /> 시간 선택 ({selectedDate.toLocaleDateString()})
              </h3>
              <div className="grid grid-cols-1 gap-3">
                {getSlots().map(slot => (
                  <button
                    key={slot}
                    onClick={() => navigate(`/booking/${theme.id}/${selectedDate.toISOString().split('T')[0]}/${slot}`)}
                    className="w-full p-4 border border-white/10 rounded-xl hover:border-white hover:bg-white/10 transition-all flex justify-between items-center group"
                  >
                    <span className="text-xl font-bold group-hover:scale-110 transition-transform">{slot}</span>
                    <span className="text-sm font-medium opacity-60">예약 가능</span>
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ThemeDetail;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { THEMES } from '../constants';
import { ChevronLeft, Info, CheckCircle2 } from 'lucide-react';
import { Theme } from '../types';

const BookingForm = () => {
  const { themeId, date, time } = useParams();
  const navigate = useNavigate();
  const [theme, setTheme] = useState<Theme | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    participants: 4,
    isCloseRequested: false,
    notes: ''
  });

  useEffect(() => {
    const savedThemes = localStorage.getItem('cs_themes');
    const themeList = savedThemes ? JSON.parse(savedThemes) : THEMES;
    const found = themeList.find((t: Theme) => t.id === themeId);
    if (found) {
        setTheme(found);
        setFormData(prev => ({ ...prev, participants: found.minPlayers }));
    }
  }, [themeId]);

  if (!theme) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone) {
        alert('예약자 성함과 휴대폰 번호를 입력해 주세요.');
        return;
    }
    navigate('/success', { state: { theme, date, time, ...formData } });
  };

  const showCloseOption = formData.participants >= theme.minPlayers;

  return (
    <div className="pt-32 pb-24 px-6 max-w-3xl mx-auto">
      <Link to={`/theme/${themeId}`} className="inline-flex items-center text-[#b3b3b3] hover:text-white mb-8 gap-1">
        <ChevronLeft size={20} /> 테마 상세로 돌아가기
      </Link>

      <div className="bg-[#1a1a1a] rounded-3xl border border-white/5 overflow-hidden">
        <div className="p-8 md:p-10 border-b border-white/5 bg-white/5">
            <h1 className="text-3xl font-bold mb-2">예약 정보 입력</h1>
            <p className="text-[#b3b3b3]">{theme.title} | {date} | {time}</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 md:p-10 space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-[#b3b3b3]">예약자 성함</label>
              <input 
                type="text" 
                required
                className="w-full bg-black/40 border border-white/10 rounded-lg p-3 focus:outline-none focus:border-white transition-colors text-white"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-[#b3b3b3]">휴대폰 번호</label>
              <input 
                type="tel" 
                required
                placeholder="010-0000-0000"
                className="w-full bg-black/40 border border-white/10 rounded-lg p-3 focus:outline-none focus:border-white transition-colors text-white"
                value={formData.phone}
                onChange={(e) => setFormData({...formData, phone: e.target.value})}
              />
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-sm font-medium text-[#b3b3b3]">참여 인원 ({theme.minPlayers}~{theme.maxPlayers}인)</label>
            <div className="flex gap-4">
              {Array.from({ length: theme.maxPlayers - theme.minPlayers + 1 }, (_, i) => theme.minPlayers + i).map(num => (
                <button
                  key={num}
                  type="button"
                  onClick={() => setFormData({...formData, participants: num})}
                  className={`w-12 h-12 rounded-lg border font-bold transition-all ${
                    formData.participants === num 
                        ? 'bg-white border-white text-black' 
                        : 'bg-transparent border-white/10 text-[#b3b3b3] hover:border-white/30'
                  }`}
                >
                  {num}
                </button>
              ))}
            </div>
          </div>

          {showCloseOption && (
            <div className="p-6 bg-red-950/10 border border-[#dc2626]/20 rounded-2xl flex items-start gap-4">
              <div className="pt-1">
                <input 
                  type="checkbox" 
                  id="closeBooking"
                  className="w-5 h-5 accent-[#dc2626]"
                  checked={formData.isCloseRequested}
                  onChange={(e) => setFormData({...formData, isCloseRequested: e.target.checked})}
                />
              </div>
              <label htmlFor="closeBooking" className="cursor-pointer">
                <p className="font-bold text-[#dc2626] mb-1">예약 마감 요청</p>
                <p className="text-xs text-[#b3b3b3] leading-relaxed">
                  최소 인원 조건이 충족되었습니다. 더 이상의 인원을 받지 않고 우리 팀끼리만 게임을 진행하길 원하시면 체크해주세요. (추가 예약 불가)
                </p>
              </label>
            </div>
          )}

          <div className="space-y-2">
            <label className="text-sm font-medium text-[#b3b3b3]">요청 사항 (선택)</label>
            <textarea 
              rows={4}
