                    setThemes(updated);
                    saveAll('cs_themes', updated);
                  }}
                  className="px-4 py-2 bg-white text-black font-bold rounded-lg text-sm flex items-center gap-2"
                >
                  <Plus size={18} /> 새 테마 등록
                </button>
              </div>
              <div className="grid grid-cols-1 gap-6">
